{"path": "/tmp/sv-b347d17a2fc746b2a1cd797f13e92425/RecipeShare/Services/RecipeService.cs", "file_text": "using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.", TotalStars = 18, RatingCount = 4 },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper", Steps = "1. Cook spaghetti in salted boiling water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra pecorino.", TotalStars = 10, RatingCount = 2 },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté garlic and ginger in butter.\n4. Add tomato sauce and spices, simmer 15 minutes.\n5. Stir in cream and add chicken pieces.\n6. Simmer 10 minutes and serve with rice.", TotalStars = 15, RatingCount = 3 },
        new Recipe { Id = 4, Title = "Vegetable Samosas", Category = "Indian", Ingredients = "Potatoes\nPeas\nCumin seeds\nCoriander\nGaram masala\nFlour\nOil for frying", Steps = "1. Boil and mash potatoes.\n2. Cook peas with spices.\n3. Mix potatoes and peas together.\n4. Prepare dough, roll into circles, cut in half.\n5. Form cones and fill with potato mixture.\n6. Deep fry until golden brown.", TotalStars = 8, RatingCount = 2 },
        new Recipe { Id = 5, Title = "Tacos al Pastor", Category = "Mexican", Ingredients = "Pork shoulder\nPineapple\nChili peppers\nAchiote paste\nCorn tortillas\nCilantro\nOnion\nLime", Steps = "1. Marinate pork in achiote and chili paste overnight.\n2. Grill pork and pineapple slices.\n3. Slice pork thinly.\n4. Warm tortillas on a griddle.\n5. Assemble with pork, pineapple, cilantro, and onion.\n6. Squeeze lime over top.", TotalStars = 20, RatingCount = 4 },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt", Steps = "1. Halve avocados and remove pits.\n2. Mash avocado to desired consistency.\n3. Dice onion, tomato, and jalapeño.\n4. Mix all ingredients together.\n5. Add lime juice and salt to taste.\n6. Serve immediately with tortilla chips.", TotalStars = 12, RatingCount = 3 },
        new Recipe { Id = 7, Title = "Beef Stir-Fry", Category = "Asian", Ingredients = "Beef sirloin\nSoy sauce\nSesame oil\nGarlic\nGinger\nBell peppers\nBroccoli\nRice", Steps = "1. Slice beef thinly against the grain.\n2. Marinate in soy sauce and sesame oil.\n3. Stir-fry beef on high heat until browned.\n4. Remove beef, add vegetables.\n5. Return beef, add sauce.\n6. Serve over steamed rice.", TotalStars = 14, RatingCount = 3 },
        new Recipe { Id = 8, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles\nShrimp or tofu\nEggs\nBean sprouts\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar", Steps = "1. Soak rice noodles in warm water.\n2. Make sauce with tamarind, fish sauce, and sugar.\n3. Stir-fry protein until cooked.\n4. Push aside, scramble eggs.\n5. Add noodles and sauce, toss together.\n6. Top with peanuts, bean sprouts, and lime.", TotalStars = 9, RatingCount = 2 },
    };

    private int _nextId = 9;

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalStars += stars;
            recipe.RatingCount++;
        }
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}
"}

