arguments.file_text:
@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>🍳 RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-3 mb-4">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetEmoji(category) @category</h4>
                    <a href="@($"category/{category.ToLower()}")" class="btn btn-primary mt-2">Browse</a>
                </div>
            </div>
        </div>
    }
</div>

<div class="mt-4">
    <a href="submit" class="btn btn-success btn-lg">📝 Submit a Recipe</a>
</div>

@code {
    [Inject] public RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private List<string> Categories { get; set; } = new();

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private string GetEmoji(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥢",
        _ => "🍽️"
    };
}

@page "/category/{CategoryName}"

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@GetEmoji(CategoryName) @CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="@($"recipe/{recipe.Id}")" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] public RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private List<RecipeShare.Models.Recipe> Recipes { get; set; } = new();

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }

    private string GetEmoji(string category) => category?.ToLower() switch
    {
        "italian" => "🍕",
        "indian" => "🍛",
        "mexican" => "🌮",
        "asian" => "🥢",
        _ => "🍽️"
    };
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
    {
        <p>@step</p>
    }

    <hr />

    <h4>Rate this Recipe</h4>
    <StarRating RecipeId="Recipe.Id" CurrentAverage="Recipe.AverageRating" CurrentCount="Recipe.RatingCount" />

    <a href="@($"category/{Recipe.Category.ToLower()}")" class="btn btn-secondary mt-4">← Back to @Recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] public RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating">
    <p>
        Average: ⭐ @Average.ToString("F1") (@Count ratings)
    </p>
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= HoveredStar ? "highlighted" : "")"
                  @onmouseover="() => HoveredStar = star"
                  @onmouseout="() => HoveredStar = 0"
                  @onclick="() => SubmitRating(star)"
                  role="button"
                  title="@($"Rate {star} star{(star > 1 ? "s" : "")}")">
                @(star <= HoveredStar ? "★" : "☆")
            </span>
        }
    </div>
    @if (Submitted)
    {
