@rendermode InteractiveServer

<div class="star-rating">
    <p>
        Average: ⭐ @Average.ToString("F1") (@Count ratings)
    </p>
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= HoveredStar ? "highlighted" : "")"
                  @onmouseover="() => HoveredStar = star"
                  @onmouseout="() => HoveredStar = 0"
                  @onclick="() => SubmitRating(star)"
                  role="button"
                  title="@($"Rate {star} star{(star > 1 ? "s" : "")}")">
                @(star <= HoveredStar ? "★" : "☆")
            </span>
        }
    </div>
    @if (Submitted)
    {
        <p class="text-success mt-2">✓ Thank you for rating!</p>
    }
</div>

<style>
    .star-rating .stars {
        font-size: 2rem;
        cursor: pointer;
        user-select: none;
    }
    .star-rating .star {
        transition: color 0.1s;
        color: #ffc107;
    }
    .star-rating .star.highlighted {
        color: #ff9800;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int CurrentCount { get; set; }
    [Inject] public RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int HoveredStar { get; set; }
    private bool Submitted { get; set; }
    private double Average { get; set; }
    private int Count { get; set; }

    protected override void OnInitialized()
    {
        Average = CurrentAverage;
        Count = CurrentCount;
    }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            Average = recipe.AverageRating;
            Count = recipe.RatingCount;
        }
        Submitted = true;
    }
}

