+                @foreach (var cat in Categories)
+                {
+                    <option value="@cat">@cat</option>
+                }
+                <option value="Other">Other</option>
+            </InputSelect>
+        </div>
+
+        <div class="mb-3">
+            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
+            <InputTextArea id="ingredients" @bind-Value="Ingredients" class="form-control" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 apples, sliced" />
+        </div>
+
+        <div class="mb-3">
+            <label for="steps" class="form-label">Steps (one per line)</label>
+            <InputTextArea id="steps" @bind-Value="Steps" class="form-control" rows="6" placeholder="1. Preheat oven to 350°F.&#10;2. Mix dry ingredients.&#10;3. Add wet ingredients." />
+        </div>
+
+        <button type="submit" class="btn btn-success" disabled="@(!IsFormValid)">Submit Recipe</button>
+        <a href="/" class="btn btn-secondary ms-2">Cancel</a>
+    </EditForm>
+}
+
+@code {
+    [Inject] public RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;
+
+    private string Title { get; set; } = string.Empty;
+    private string SelectedCategory { get; set; } = string.Empty;
+    private string Ingredients { get; set; } = string.Empty;
+    private string Steps { get; set; } = string.Empty;
+    private bool IsSubmitted { get; set; }
+    private List<string> Categories { get; set; } = new();
+
+    private bool IsFormValid =>
+        !string.IsNullOrWhiteSpace(Title) &&
+        !string.IsNullOrWhiteSpace(SelectedCategory) &&
+        !string.IsNullOrWhiteSpace(Ingredients) &&
+        !string.IsNullOrWhiteSpace(Steps);
+
+    protected override void OnInitialized()
+    {
+        Categories = RecipeService.GetCategories();
+    }
+
+    private void HandleSubmit()
+    {
+        if (!IsFormValid) return;
+        RecipeService.AddRecipe(Title, SelectedCategory, Ingredients, Steps);
+        IsSubmitted = true;
+    }
+
+    private void Reset()
+    {
+        Title = string.Empty;
+        SelectedCategory = string.Empty;
+        Ingredients = string.Empty;
+        Steps = string.Empty;
+        IsSubmitted = false;
+    }
+}
+

